@code {
    /// <summary>
    /// Returns null when the current page opts out of interactivity (e.g. the Privacy page
    /// uses <c>@rendermode null</c>), otherwise applies global InteractiveServer mode.
    /// Pages that need static SSR (to access HttpContext) set their render mode to null;
    /// all other pages get interactive server rendering as the default.
    /// </summary>
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode => ComponentRenderModeIsDisabled
        ? null
        : RenderMode.InteractiveServer;

    /// <summary>
    /// When a page declares <c>@rendermode null</c>, the framework will not assign an
    /// interactive render mode. We detect this via an endpoint metadata attribute.
    /// </summary>
    private bool ComponentRenderModeIsDisabled
    {
        get
        {
            var endpoint = HttpContext?.GetEndpoint();
            var metadata = endpoint?.Metadata.GetMetadata<ComponentRenderModeAttribute>();
            // If the attribute exists but its Mode is null, the page explicitly opted out.
            return metadata is { Mode: null };
        }
    }
}
"}

